'use client';
import React, { useState, useEffect } from 'react';

// 1. Verifique se onLogout está EXATAMENTE assim dentro das chaves
function Topo({ totalItens, abrirCarrinho, verHistorico, usuarioLogado, onLogout }) {
  const [tempo, setTempo] = useState(86400);

  useEffect(() => {
    const timer = setInterval(() => {
      setTempo(prev => (prev > 0 ? prev - 1 : 86400));
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const formatarTempo = (segundos) => {
    const h = Math.floor(segundos / 3600);
    const m = Math.floor((segundos % 3600) / 60);
    const s = segundos % 60;
    const format = (num) => String(num).padStart(2, '0');
    return `${format(h)}h ${format(m)}m ${format(s)}s`;
  };

  return (
   <header className="topo-container" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '10px 20px', backgroundColor: '#fff', borderBottom: '2px solid #eee' }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
        <img src="slog.png" alt="Logo" className="imagem-topo" style={{ height: '60px' }} />
        <h1 style={{ fontSize: '1.2rem', margin: 0 }}>Amigo do Bairro</h1>
      </div>

      <div className="topo-centro" style={{ textAlign: 'center', flex: 1 }}>
        <div className="balao-ofertas" style={{ display: 'inline-block', padding: '5px 15px', borderRadius: '20px', background: '#fff0f0' }}>
          <span className="texto-pisca" style={{ color: 'red', fontWeight: 'bold', display: 'block' }}>🔥 OFERTA DA SEMANA 🔥</span>
          <span className="timer-destaque" style={{ fontSize: '0.9rem' }}>{formatarTempo(tempo)}</span>
        </div>
      </div>

      <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
        <button onClick={abrirCarrinho} className="botao-carrinho" style={{ padding: '8px', cursor: 'pointer' }}>
          🛒 Carrinho <span className="badge" style={{ background: 'red', color: 'white', padding: '2px 6px', borderRadius: '50%' }}>{totalItens}</span>
        </button>

        <button 
          className="btn-historico" 
          onClick={verHistorico} 
          onDoubleClick={() => typeof onLogout === 'function' && onLogout()}
          style={{ cursor: 'pointer', padding: '8px' }}
        >
          {usuarioLogado ? `👤 ${usuarioLogado.nome.split(' ')[0]} (Sair)` : "📋 Pedidos"}
        </button>
      </div>
    </header>
  );
}

export default Topo;
